#include <iostream>
#include <string>
#include <iomanip>
#include <vector>
#include <tuple>

class Date {
private:
    int day;
    int month;
    int year;

public:
    Date(int d, int m, int y) : day(d), month(m), year(y) {}

    bool isValidDate() {
        if (month < 1 || month > 12) return false;
        if (day < 1 || day > 31) return false;

        bool isLeap = (year % 4 == 0 && year % 100 != 0);

        int daysInMonth;
        switch (month) {
            case 2:
                daysInMonth = isLeap ? 29 : 28;
                break;
            case 4: case 6: case 9: case 11:
                daysInMonth = 30;
                break;
            default:
                daysInMonth = 31;
                break;
        }

        return day <= daysInMonth;
    }

    void displayDate() {
        std::cout << std::setfill('0') << std::setw(2) << day << '/'
                  << std::setfill('0') << std::setw(2) << month << '/'
                  << std::setfill('0') << std::setw(4) << year;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::vector<std::tuple<int, int, int>> inputs = {
        {15, 3, 2023},
        {29, 2, 2024},
        {29, 2, 2023},
        {31, 4, 2023},
        {31, 1, 2023},
        {1, 13, 2023},
        {1, 0, 2023},
        {0, 1, 2023},
        {29, 2, 2000},
        {29, 2, 1900},
        {1, 1, 0},
        {1, 1, -2023}
    };

    for (const auto& input_tuple : inputs) {
        int d = std::get<0>(input_tuple);
        int m = std::get<1>(input_tuple);
        int y = std::get<2>(input_tuple);

        Date date(d, m, y);
        std::cout << "Input: " << d << " " << m << " " << y << "\n";
        std::cout << "isValid: " << (date.isValidDate() ? "true" : "false") << ", display: ";
        date.displayDate();
        std::cout << "\n";
    }
    return 0;
}
